import React from "react";
import { Link } from "react-router-dom";
import { FaUser } from "react-icons/fa"; // account icon
import "../index.css";

function Navbar({ user }) { // ✅ Receive user as prop
  return (
    <nav className="navbar">
      {/* Brand Name */}
      <div className="logo">ElectroStore</div>

      {/* Nav Links */}
      <ul className="nav-links">
        <li><Link to="/">Home</Link></li>
        <li><Link to="/shop">Shop</Link></li>
        <li><Link to="/about">About Us</Link></li>
        <li><Link to="/contact">Contact</Link></li>
        <li><Link to="/seller">Seller Dashboard</Link></li>
      </ul>

      {/* Search Bar */}
      <div className="search-bar">
        <input type="text" placeholder="Search products..." />
        <button>🔍</button>
      </div>

      {/* Account Section */}
      <div className="account">
        <Link to={user ? "#" : "/login"} className="account-link">
          <FaUser className="account-icon" />
          <span>{user ? user.name : "Account"}</span>
        </Link>
        {user && (
          <ul className="account-dropdown">
            <li><Link to="/cart">Cart</Link></li>
            <li><Link to="/orders">Orders</Link></li>
            <li className="logout">
              <Link to="/" onClick={() => window.location.reload()}>
                Logout
              </Link>
            </li>
          </ul>
        )}
      </div>
    </nav>
  );
}

export default Navbar;
